#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input span
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    NetworkPacket packet;

    // Use operator>> to read packet_id
    stream >> packet.packet_id;

    // Use operator>> with prefixed adaptor to read username
    stream >> hexi::prefixed(packet.username);

    // Read scores vector: first read the count (uint32_t), then use read_container
    uint32_t score_count;
    stream >> score_count;
    stream.read_container(packet.scores, score_count);

    // Use operator>> with null_terminated adaptor to read metadata
    stream >> hexi::null_terminated(packet.metadata);

    // Use skip to skip any remaining padding bytes
    if (stream.total_read() < buffer.size()) {
        stream.skip(buffer.size() - stream.total_read());
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from the input span
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    // Create binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    PacketInfo info;

    // Use span() to get a zero-copy view of the packet_id
    auto packet_id_span = stream.span<uint32_t>(1);
    info.packet_id = *packet_id_span;

    // Use operator>> with prefixed adaptor to read username as string_view
    std::string_view username_sv;
    stream >> hexi::prefixed(username_sv);
    info.username = username_sv;

    // Use skip to skip the scores vector: first read the count, then skip the data
    uint32_t score_count;
    stream >> score_count;
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}
```

**Explanation:**

1. **deserialize_packet function:**
   - Creates a `buffer_adaptor` from the input span to provide the buffer interface
   - Creates a `binary_stream` using the buffer adaptor for serialization operations
   - Uses `operator>>` to deserialize each field in order:
     - `packet_id` as a simple uint32_t
     - `username` using `prefixed` adaptor for length-prefixed strings
     - `scores` vector by first reading the count, then using `read_container` to deserialize the vector elements
     - `metadata` using `null_terminated` adaptor for zero-copy string reading
   - Skips any remaining padding bytes to ensure the stream is properly positioned

2. **extract_packet_info function:**
   - Similar setup with buffer adaptor and binary stream
   - Uses `span()` to get a zero-copy view of the packet_id (first 4 bytes)
   - Uses `operator>>` with `prefixed` adaptor to read username as `string_view` (no data copying)
   - Reads the score count and skips the actual score data using `skip()`
   - Returns the extracted information without fully deserializing the packet

Both implementations follow the hexi library patterns and correctly handle the serialization/deserialization operations as specified in the assessment objectives.

