std::vector<uint8_t> serialize_with_padding(const PaddedData& packet) {
    // Create a buffer and writer instance
    hexi::Buffer buffer;
    hexi::Writer writer(buffer);

    // Write header
    writer << packet.header;

    // Write data with prefix (automatically adds length prefix)
    writer << packet.data;

    // Write 16 bytes of padding filled with 0x00
    writer.fill<16>(0x00);

    // Write footer
    writer << packet.footer;

    // Return the buffer content
    return buffer;
}

