        double p;
        adaptor.read(&p, 1);
        hexi::endian::little_to_native_inplace(p);
        pressure = p;
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    // Create buffer and adaptor
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream and serialize
    hexi::binary_stream stream(adaptor);
    stream.serialise(data);

    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    // Create adaptor from span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream and deserialize
    hexi::binary_stream stream(adaptor);
    MeasurementData data;
    stream.deserialise(data);

    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    // Create adaptor
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream
    hexi::binary_stream stream(adaptor);

    SensorInfo info;

    // Extract sensor name using view (null-terminated string)
    info.sensor_name = stream.view();

    // Check if there's enough data for sensor_id
    if (stream.read_max() < sizeof(uint32_t)) {
        // Not enough data, return partial info
        return info;
    }

    // Read sensor_id
    stream.read(&info.sensor_id, 1);

    // Skip remaining data
    stream.skip(stream.read_max());

    return info;
}
